            curr_str += c
    return curr_str

def findMin(nums):
    l, r = 0, len(nums) - 1
    while l < r:
        mid = (l + r) // 2
        if nums[mid] > nums[r]:
            l = mid + 1
        else:
            r = mid
    return nums[l]

def shipWithinDays(weights, days):
    def feasible(cap):
        day_count = 1
        load = 0
        for w in weights:
            if load + w > cap:
                day_count += 1
                load = 0
            load += w
        return day_count <= days

    lo, hi = max(weights), sum(weights)
    while lo < hi:
        mid = (lo + hi) // 2
        if feasible(mid):
            hi = mid
        else:
            lo = mid + 1
    return lo

def combinationSum(candidates, target):
    result = []
    def backtrack(start, path, total):
        if total == target:
            result.append(path[:])
            return
        if total > target:
            return
        for i in range(start, len(candidates)):
            path.append(candidates[i])
            backtrack(i, path, total + candidates[i])  # i not i+1: reuse allowed
            path.pop()
    backtrack(0, [], 0)
    return result

def rob(nums):
    def linear_rob(arr):
        prev, curr = 0, 0
        for n in arr:
            prev, curr = curr, max(curr, prev + n)
        return curr
    if len(nums) == 1:
        return nums[0]
    return max(linear_rob(nums[:-1]), linear_rob(nums[1:]))

def numDecodings(s):
    dp = [0] * (len(s) + 1)
    dp[0] = 1
    dp[1] = 0 if s[0] == '0' else 1
    for i in range(2, len(s) + 1):
        one = int(s[i-1])
        two = int(s[i-2:i])
        if one != 0:
            dp[i] += dp[i-1]
        if 10 <= two <= 26:
            dp[i] += dp[i-2]
    return dp[-1]

def longestPalindromeSubseq(s):
    s_rev = s[::-1]
    m, n = len(s), len(s_rev)
    dp = [[0] * (n + 1) for _ in range(m + 1)]
    for i in range(1, m + 1):
        for j in range(1, n + 1):
            if s[i-1] == s_rev[j-1]:
                dp[i][j] = dp[i-1][j-1] + 1
            else:
                dp[i][j] = max(dp[i-1][j], dp[i][j-1])
    return dp[m][n]

def isInterleave(s1, s2, s3):
    m, n = len(s1), len(s2)
    if m + n != len(s3):
        return False
    dp = [[False] * (n + 1) for _ in range(m + 1)]
    dp[0][0] = True
    for i in range(1, m + 1):
        dp[i][0] = dp[i-1][0] and s1[i-1] == s3[i-1]
    for j in range(1, n + 1):
        dp[0][j] = dp[0][j-1] and s2[j-1] == s3[j-1]
    for i in range(1, m + 1):
        for j in range(1, n + 1):
            dp[i][j] = (dp[i-1][j] and s1[i-1] == s3[i+j-1]) or \
                       (dp[i][j-1] and s2[j-1] == s3[i+j-1])
    return dp[m][n]

def eraseOverlapIntervals(intervals):
    if not intervals:
        return 0
    intervals.sort(key=lambda x: x[1])  # sort by end time
    last_end = intervals[0][1]
    removals = 0
    for start, end in intervals[1:]:
        if start >= last_end:  # no overlap — keep it
            last_end = end
        else:
            removals += 1  # overlap — remove current (keep the one with earlier end)
    return removals
